module gray_code_counter (
    input rst_clk,
    input reset,
    output reg [1:0] gray
);

    always @(posedge rst_clk or posedge reset) begin
        if (reset)
            gray <= 2'b00;
        else begin
            case (gray)
                2'b00: gray <= 2'b01;
                2'b01: gray <= 2'b11;
                2'b11: gray <= 2'b10;
                2'b10: gray <= 2'b00;
                default: gray <= 2'b00;
            endcase
        end
    end

endmodule
